appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};

    // 1. Scrape the JSON for AI references (Simulated extraction based on your APK data)
    let aiLibraries = [];

    // Check for Google MLKit and TensorFlow Lite in Services and Providers
    if (rawData.services && rawData.services.some(s => s.includes("MlKit"))) {
      aiLibraries.push({
        name: "Google MLKit Component Service",
        type: "Background Service",
        status: "Sanctioned",
        risk: "Safe",
        rawClass: "com.google.mlkit.common.internal.MlKitComponentDiscoveryService"
      });
    }
    if (rawData.providers && rawData.providers.some(p => p.includes("mlmodel"))) {
      aiLibraries.push({
        name: "Onfido ML Model Downloader",
        type: "Content Provider",
        status: "Sanctioned",
        risk: "Warning",
        rawClass: "com.onfido.android.sdk.capture.utils.mlmodel.OnfidoMlModelDownloaderInternal"
      });
    }

    // Add explicit observation of TensorFlow Lite from api_native_code
    aiLibraries.push({
      name: "TensorFlow Lite Native Interpreter",
      type: "Native Library Executable",
      status: "Unsanctioned",
      risk: "Critical",
      rawClass: "org/tensorflow/lite/NativeInterpreterWrapper"
    });

    // 2. Update Stats Cards
    document.getElementById('total-sdks').innerText = aiLibraries.length;
    const unsanctionedCount = aiLibraries.filter(lib => lib.status === 'Unsanctioned').length;
    document.getElementById('unsanctioned-models').innerText = unsanctionedCount;

    // For endpoint metrics (Mocked as an observed signal calculation)
    document.getElementById('inference-endpoints').innerText = "2 Active";

    // 3. Populate Dependencies Table
    const tbody = document.getElementById('dependencies-table-body');
    tbody.innerHTML = ''; // Clear loading text

    if (aiLibraries.length === 0) {
      tbody.innerHTML = '<tr><td colspan="4" style="text-align: center;">No AI dependencies observed in application payload.</td></tr>';
      return;
    }
    aiLibraries.forEach(lib => {
      const tr = document.createElement('tr');

      // Component Name
      const tdName = document.createElement('td');
      tdName.innerHTML = `<strong>${lib.name}</strong><br><code>${lib.rawClass}</code>`;

      // Type
      const tdType = document.createElement('td');
      tdType.textContent = lib.type;

      // Status Badge
      const tdStatus = document.createElement('td');
      const statusBadge = document.createElement('span');
      statusBadge.className = lib.status === 'Sanctioned' ? 'badge badge-sanctioned' : 'badge badge-unsanctioned';
      statusBadge.textContent = lib.status;
      tdStatus.appendChild(statusBadge);

      // Risk Label Badge
      const tdRisk = document.createElement('td');
      const riskBadge = document.createElement('span');
      if (lib.risk === 'Critical') riskBadge.className = 'badge badge-critical';else if (lib.risk === 'Warning') riskBadge.className = 'badge badge-warning';else riskBadge.className = 'badge badge-safe';
      riskBadge.textContent = lib.risk;
      tdRisk.appendChild(riskBadge);
      tr.appendChild(tdName);
      tr.appendChild(tdType);
      tr.appendChild(tdStatus);
      tr.appendChild(tdRisk);
      tbody.appendChild(tr);
    });
  });
});

